#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  auto conn = sqlgen::sqlite::connect(db_path);
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  for (const auto& record : records) {
    auto result = sqlgen::insert(conn.value(), record);
    if (!result) {
      throw std::runtime_error("Failed to insert record");
    }
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const auto& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path);
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  // Create update statement based on table name and primary key
  if (table_name == "Student") {
    auto result = sqlgen::update(conn.value())
                      .set(col_name.c_str() = new_value)
                      .where("SNo"_ = std::to_string(record_id))
                      .template for_table<Student>();
    if (!result) {
      throw std::runtime_error("Failed to update student record");
    }
  } else if (table_name == "Course") {
    auto result = sqlgen::update(conn.value())
                      .set(col_name.c_str() = new_value)
                      .where("CID"_ = record_id)
                      .template for_table<Course>();
    if (!result) {
      throw std::runtime_error("Failed to update course record");
    }
  } else if (table_name == "Score") {
    auto result = sqlgen::update(conn.value())
                      .set(col_name.c_str() = new_value)
                      .where("ScID"_ = record_id)
                      .template for_table<Score>();
    if (!result) {
      throw std::runtime_error("Failed to update score record");
    }
  } else if (table_name == "Major") {
    auto result = sqlgen::update(conn.value())
                      .set(col_name.c_str() = new_value)
                      .where("MID"_ = record_id)
                      .template for_table<Major>();
    if (!result) {
      throw std::runtime_error("Failed to update major record");
    }
  } else {
    throw std::runtime_error("Unknown table name: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  auto conn = sqlgen::sqlite::connect(db_path);
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  // Create delete statement based on table name and primary key
  if (table_name == "Student") {
    auto result = sqlgen::remove(conn.value())
                      .where("SNo"_ = record_id)
                      .template for_table<Student>();
    if (!result) {
      throw std::runtime_error("Failed to delete student record");
    }
  } else if (table_name == "Course") {
    auto result = sqlgen::remove(conn.value())
                      .where("CID"_ = std::stoi(record_id))
                      .template for_table<Course>();
    if (!result) {
      throw std::runtime_error("Failed to delete course record");
    }
  } else if (table_name == "Score") {
    auto result = sqlgen::remove(conn.value())
                      .where("ScID"_ = std::stoi(record_id))
                      .template for_table<Score>();
    if (!result) {
