Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  // View to store course enrollment statistics
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  // Connect to the SQLite database
  sqlgen::SQLiteDatabase db("test_db.sqlite");

  // Create Course and Enrollment tables
  db.create_table<Course>();
  db.create_table<Enrollment>();

  // Query to calculate enrollment statistics per course
  auto query = db.prepare(
    sqlgen::select(
      Course::title,
      sqlgen::count(Enrollment::enrollment_id).as("student_count"),
      sqlgen::avg(Enrollment::grade).as("avg_grade")
    )
    .from<Course>()
    .left_join<Enrollment>().on(Course::course_id == Enrollment::course_id)
    .group_by(Course::course_id, Course::title)
  );

  // Execute the query and get results
  auto results = query.template execute<CourseStatsView>();

  // Convert results to CourseStats vector
  std::vector<CourseStats> stats;
  stats.reserve(results.size());

  for (const auto& result : results) {
    stats.push_back(CourseStats{
      result.title,
      result.student_count,
      result.avg_grade
    });
  }

  return stats;
}

}  // namespace query_course_enrollment_stats
```

