  static_assert(std::is_same_v<ToType, Nothing>,
                "You cannot call to<...> before where(...).");
  return SelectFrom<TableOrQueryType, AliasType, FieldsType, JoinsType,
                    ConditionType, GroupByType, OrderByType, LimitType,
                    ToType>{.fields_ = _s.fields_,
                            .from_ = _s.from_,
                            .joins_ = _s.joins_,
                            .where_ = _where.condition};
}

template <rfl::internal::StringLiteral _alias, class QueryType,
          class... FieldTypes>
inline auto select_from(const QueryType& _query, const FieldTypes&... _fields) {
  using FieldsType =
      rfl::Tuple<typename internal::GetColType<FieldTypes>::Type...>;
  return SelectFrom<QueryType, Literal<_alias>, FieldsType>{
      .fields_ =
          FieldsType(internal::GetColType<FieldTypes>::get_value(_fields)...),
      .from_ = _query};
}

template <class ConditionType>
inline auto where(const ConditionType& _cond) {
  return Where<std::remove_cvref_t<ConditionType>>{.condition = _cond};
};

auto operator()(const auto& _conn) const {
    if constexpr (std::ranges::input_range<std::remove_cvref_t<Type>> ||
                  internal::is_range_v<Type>) {
      return read_impl<Type, WhereType, OrderByType, LimitType>(_conn, where_,
                                                                limit_);

    } else {
      return read_impl<std::vector<Type>, WhereType, OrderByType, LimitType>(
                 _conn, where_, limit_)
          .and_then([](auto&& _vec) -> Result<Type> {
            if (_vec.size() != 1) {
              return error(
                  "Because the provided type was not a container, the query "
                  "needs to return exactly one result, but it did return " +
                  std::to_string(_vec.size()) + " results.");
            }
            return std::move(_vec[0]);
          });
    }
  }

dynamic::CreateTable to_create_table(const bool _if_not_exists = true) {
  using NamedTupleType = rfl::named_tuple_t<std::remove_cvref_t<T>>;
  using Fields = typename NamedTupleType::Fields;

  static_assert(get_table_or_view<T>() == dynamic::TableOrView::table,
                "You cannot create a view using create_table(...).");

  return dynamic::CreateTable{
      .table =
          dynamic::Table{.name = get_tablename<T>(), .schema = get_schema<T>()},
      .columns = make_columns<Fields>(
          std::make_integer_sequence<int, rfl::tuple_size_v<Fields>>()),
      .if_not_exists = _if_not_exists};
}

