std::vector<DepProj> right_join_departments_projects() {
  // Create database connection
  sqlgen::sqlite::database db("test_db.sqlite");

  // Define table objects
  auto departments = sqlgen::table<Department>("Department");
  auto projects = sqlgen::table<Project>("Project");

  // Perform RIGHT JOIN: Include all departments (even those without projects)
  // Note: Since SQLite doesn't natively support RIGHT JOIN, we simulate it with LEFT JOIN
  // by swapping the tables and using the reverse relationship
  auto results = sqlgen::read<DepProj>(db,
    sqlgen::left_join(projects, departments, 
      sqlgen::on(projects.department_id, departments.department_id))
    .columns(
      departments.name.as(&DepProj::department_name),
      projects.name.as(&DepProj::project_name)
    )
  );

  return results;
}

}  // namespace right_join_departments_projects
