 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Create database connection
    sqlgen::SQLiteDatabase db("test_db.sqlite");

    // Create table if it doesn't exist
    db.execute(R"(
      CREATE TABLE IF NOT EXISTS Inventory (
        item_id INTEGER PRIMARY KEY,
        name TEXT NOT NULL,
        quantity INTEGER NOT NULL
      )
    )");

    // Perform upsert operations using replace (SQLite's INSERT OR REPLACE)
    for (const auto& item : items) {
      auto stmt = db.prepare("REPLACE INTO Inventory (item_id, name, quantity) VALUES (?, ?, ?)");
      stmt.bind(1, item.item_id.value);
      stmt.bind(2, item.name);
      stmt.bind(3, item.quantity);
      stmt.execute();
    }

    // Verify upsert behavior by reading back all items
    auto verify_stmt = db.prepare("SELECT item_id, name, quantity FROM Inventory ORDER BY item_id");
    auto result = verify_stmt.executeQuery();

    std::vector<Inventory> retrieved_items;
    while (result.next()) {
      Inventory item;
      item.item_id.value = result.getInt(0);
      item.name = result.getString(1);
      item.quantity = result.getInt(2);
      retrieved_items.push_back(item);
    }

    // Check if all inserted items are present and correct
    for (const auto& original_item : items) {
      bool found = false;
      for (const auto& retrieved_item : retrieved_items) {
        if (retrieved_item.item_id.value == original_item.item_id.value) {
          if (retrieved_item.name != original_item.name || 
              retrieved_item.quantity != original_item.quantity) {
            std::cerr << "Verification failed for item_id: " << original_item.item_id.value 
                      << " - data mismatch" << std::endl;
            return false;
          }
          found = true;
          break;
        }
      }

      if (!found) {
        std::cerr << "Verification failed for item_id: " << original_item.item_id.value 
                  << " - item not found" << std::endl;
        return false;
      }
    }

    std::cout << "Upsert operation completed successfully. " 
              << items.size() << " items processed." << std::endl;
    return true;

  } catch (const std::exception& e) {
    std::cerr << "Error in upsert_inventory_items: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace upsert_inventory_items
