#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>
#include <iostream>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct UserFriendCount {
  int user_id;
  std::string username;
  int friend_count;
};

struct MutualFriendsResult {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends_count;
};

struct FriendRecommendation {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    std::vector<FriendConnection> results;

    try {
        // Create in-memory database
        sqlgen::SQLite db(":memory:");

        // Create tables
        db.createTable<User>("User", {
            {"user_id", &User::user_id, "PRIMARY KEY"},
            {"username", &User::username, "NOT NULL UNIQUE"},
            {"email", &User::email, "NOT NULL UNIQUE"},
            {"join_date", &User::join_date, "NOT NULL"},
            {"city", &User::city}
        });

        db.createTable<Friendship>("Friendship", {
            {"user_id1", &Friendship::user1_id, "FOREIGN KEY REFERENCES User(user_id)"},
            {"user_id2", &Friendship::user2_id, "FOREIGN KEY REFERENCES User(user_id)"},
            {"friendship_date", &Friendship::created_at, "NOT NULL"},
            {"PRIMARY KEY", "", "(user_id1, user_id2)"}
        });

        // Insert data
        for (const auto& user : users) {
            db.insert("User", user);
        }

        for (const auto& friendship : friendships) {
            db.insert("Friendship", friendship);
        }

        // 1. Find mutual friends using SELF-JOIN
        auto mutual_friends = db.executeQuery<MutualFriendsResult>(
            "SELECT u1.username as user1_name, u2.username as user2_name, COUNT(f1.user_id2) as mutual_friends_count "
            "FROM User u1 "
            "INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1 "
            "INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1 "
            "INNER JOIN User u2 ON f2.user_id2 = u2.user_id "
            "WHERE u1.user_id < u2.user_id "
            "  AND EXISTS ( "
            "    SELECT 1 FROM Friendship f3  "
            "    WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id "
            "  ) "
            "GROUP BY u1.user_id, u2.user_id "
            "HAVING COUNT(f1.user_id2) > 0"
        );

        // 2. Find users with more than average number of friends using nested query
        auto popular_users = db.executeQuery<UserFriendCount>(
            "SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count "
            "FROM User u "
            "LEFT JOIN Friendship f ON u.user_id = f.user_id1 "
            "GROUP BY u.user_id, u.username "
            "HAVING friend_count > ( "
            "  SELECT AVG(friend_count)  "
            "  FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1) "
            ") "
            "ORDER BY friend_count DESC"
        );

        // 3. Find friend-of-friend relationships
        auto friend_of_friend = db.executeQuery<FriendConnection>(
            "SELECT DISTINCT u1.username as user1_name, u3.username as user2_name "
            "FROM User u1 "
            "JOIN Friendship f1 ON u1.user_id = f1.user_id1 "
            "JOIN User u2 ON f1.user_id2 = u2.user_id "
            "JOIN Friendship f2 ON u2.user_id = f2.user_id1 "
            "JOIN User u3 ON f2.user_id2 = u3.user_id "
            "WHERE u1.user_id != u3.user_id "
            "  AND NOT EXISTS ( "
            "    SELECT 1 FROM Friendship f3 "
            "    WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id "
            "  )"
        );

        // 4. Count friends per user
        auto friends_per_user = db.executeQuery<UserFriendCount>(
            "SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count "
            "FROM User u "
            "LEFT JOIN Friendship f ON u.user_id = f.user_id1 "
            "GROUP BY u.user_id, u.username "
            "ORDER BY friend_count DESC"
        );

        // 5. Find users in the same city who are not yet friends (recommendation)
        auto city_recommendations = db.executeQuery<FriendRecommendation>(
            "SELECT u1.username as user1_name, u2.username as user2_name, u1.city as city "
            "FROM User u1 "
            "JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id "
            "WHERE u1.city IS NOT NULL "
            "  AND NOT EXISTS ( "
            "    SELECT 1 FROM Friendship f "
            "    WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id) "
            "       OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id) "
            "  )"
        );

        // Return friend-of-friend relationships as the main result
        for (const auto& connection : friend_of_friend) {
            results.push_back({connection.user1_name, connection.user2_name});
        }

        // Print analysis results for demonstration
        std::cout << "=== Social Network Analysis Results ===\n";

        std::cout << "\n1. Mutual Friends:\n";
        for (const auto& mf : mutual_friends) {
            std::cout << mf.user1_name << " and " << mf.user2_name 
                      << " have " << mf.mutual_friends_count << " mutual friends\n";
        }

        std::cout << "\n2. Popular Users (above average friends):\n";
        for (const auto& pu : popular_users) {
            std::cout << pu.username << " has " << pu.friend_count << " friends\n";
        }

        std::cout << "\n3. Friend-of-Friend Relationships:\n";
        for (const auto& fof : friend_of_friend) {
            std::cout << fof.user1_name << " -> [friend] -> [friend] -> " << fof.user2_name << "\n";
        }

        std::cout << "\n4. Friends Count per User:\n";
        for (const auto& fpu : friends_per_user) {
            std::cout << fpu.username << ": " << fpu.friend_count << " friends\n";
        }

        std::cout << "\n5. City-based Friend Recommendations:\n";
        for (const auto& rec : city_recommendations) {
            std::cout << rec.user1_name << " and " << rec.user2_name 
                      << " (both in " << rec.city << ") should connect!\n";
        }

    } catch (const std::exception& e) {
        std::cerr << "Database error: " << e.what() << std::endl;
    }

    return results;
}

}  // namespace analyze_social_network

