#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  // Create an in-memory SQLite database
  sqlgen::sqlite db(":memory:");

  // Create the OrderItem table
  db.execute(R"(
    CREATE TABLE OrderItem (
      item_id INTEGER PRIMARY KEY,
      order_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      unit_price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate REAL
    )
  )");

  // Insert all items into the table
  auto insert_stmt = db.prepare<OrderItem>(R"(
    INSERT INTO OrderItem (item_id, order_id, product_id, unit_price, quantity, discount_rate, tax_rate)
    VALUES (?, ?, ?, ?, ?, ?, ?)
  )");

  for (const auto& item : items) {
    insert_stmt.insert(item);
  }

  // Execute the comprehensive metrics query
  auto results = db.query<OrderMetrics>(R"(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0.0) as discount_rate,
      COALESCE(tax_rate, 0.0) as tax_rate,
      (unit_price * quantity) as gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0.0)/100)) as discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0.0)/100) * (1 + COALESCE(tax_rate, 0.0)/100)) as final_total,
      (unit_price * quantity * 1.0 / quantity) as unit_cost,
      (quantity % 10) as quantity_group,
      (unit_price * 0.3) as estimated_profit
    FROM OrderItem
    ORDER BY item_id
  )");

  // Convert the query results to a vector
  std::vector<OrderMetrics> metrics;
  for (auto& row : results) {
    metrics.push_back(std::move(row));
  }

  return metrics;
}

}  // namespace calculate_order_metrics

