  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  try {
    // Create database connection
    sqlgen::Database<sqlgen::SQLite> db("test_db.sqlite");

    // Enable foreign key constraints (required for SQLite)
    db.execute("PRAGMA foreign_keys = ON");

    // Create tables
    db.create_table<Parent>();
    db.create_table<Child>();

    // Insert parent record
    Parent parent{1, "Test Parent"};
    db.insert(parent);

    // Insert child records with the same parent_id
    Child child1{1, 1, "First child"};
    Child child2{2, 1, "Second child"};
    db.insert(child1);
    db.insert(child2);

    // Verify initial child count
    auto initial_children = db.select<Child>(sqlgen::where(&Child::parent_id) == 1);
    if (initial_children.size() != 2) {
      std::cout << "Initial child count verification failed" << std::endl;
      return false;
    }

    // Delete parent record (should cascade to child records)
    db.remove<Parent>(sqlgen::where(&Parent::parent_id) == 1);

    // Verify child records were automatically deleted
    auto remaining_children = db.select<Child>(sqlgen::where(&Child::parent_id) == 1);

    // Verify parent was deleted
    auto remaining_parents = db.select<Parent>(sqlgen::where(&Parent::parent_id) == 1);

    bool success = (remaining_children.size() == 0) && (remaining_parents.size() == 0);

    if (success) {
      std::cout << "Cascade delete demonstration successful: " 
                << "Child records were automatically deleted when parent was deleted" << std::endl;
    } else {
