#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace column_is_null_checks {

struct Profile {
  sqlgen::PrimaryKey<int> profile_id;
  std::string display_name;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

struct Result {
  int profile_id;
  std::string display_name;
};

std::vector<Result> column_is_null_checks() {
  // Connect to the SQLite database
  sqlgen::SQLite db{"test_db.sqlite"};

  // Create the Profile table if it doesn't exist
  db.create_table<Profile>();

  // Query to filter rows where bio IS NULL and avatar_url IS NOT NULL
  auto results = db.query(
    sqlgen::select(
      sqlgen::columns(&Profile::profile_id, &Profile::display_name),
      sqlgen::from<Profile>(),
      sqlgen::where(
        sqlgen::is_null(&Profile::bio) && sqlgen::is_not_null(&Profile::avatar_url)
      )
    )
  );

  // Convert the results to the desired format
  std::vector<Result> filtered_results;
  for (const auto& row : results) {
    filtered_results.push_back(Result{
      .profile_id = row.profile_id,
      .display_name = row.display_name
    });
  }

  return filtered_results;
}

}  // namespace column_is_null_checks
