    db.update<Account>()
      .set(&Account::balance, 2500.0)
      .set(&Account::status, "active")
      .where(sqlgen::column(&Account::account_id) == 2)
      .execute();

    // Update all active accounts to have a 10% bonus
    db.update<Account>()
      .set(&Account::balance, sqlgen::column(&Account::balance) * 1.1)
      .where(sqlgen::column(&Account::status) == "active")
      .execute();

    // 5. Verify changes persisted
    auto updated_account1 = db.select<Account>()
      .where(sqlgen::column(&Account::account_id) == 1)
      .template execute_one<Account>();

    auto updated_account2 = db.select<Account>()
      .where(sqlgen::column(&Account::account_id) == 2)
      .template execute_one<Account>();

    auto updated_account3 = db.select<Account>()
      .where(sqlgen::column(&Account::account_id) == 3)
      .template execute_one<Account>();

    // Verify account1 updates
