      std::cerr << "Account1 update verification failed" << std::endl;
      return false;
    }

    // Verify account2 updates (should have 10% bonus applied after the base update)
    if (updated_account2.balance != (2500.0 * 1.1) || updated_account2.status != "active") {
      std::cerr << "Account2 update verification failed" << std::endl;
      return false;
    }

    // Verify account3 updates (should have 10% bonus applied)
    if (std::abs(updated_account3.balance - (3000.0 * 1.1)) > 0.01 || updated_account3.status != "active") {
      std::cerr << "Account3 update verification failed" << std::endl;
      return false;
