Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Open the database connection
  auto db = sqlgen::sqlite::Database::open("test_db.sqlite");

  // Since SQLite doesn't directly support FULL JOIN, we simulate it using LEFT JOIN and UNION
  // This query combines:
  // 1. All suppliers with their products (LEFT JOIN)
  // 2. All products that don't have a supplier (using a LEFT JOIN with NULL check)
  std::string sql = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id

    UNION ALL

    SELECT NULL as supplier_name, p.name as product_name
    FROM Product p
    WHERE p.supplier_id NOT IN (SELECT supplier_id FROM Supplier)
  )";

  // Execute the query and return the results
  return db.query<SupProd>(sql);
}

}  // namespace full_join_suppliers_products
```

