 */
std::vector<SupProd> full_join_suppliers_products() {
  // Open the database connection
  auto db = sqlgen::sqlite::Database::open("test_db.sqlite");

  // Simulate FULL JOIN using LEFT JOIN and RIGHT JOIN (via reversed LEFT JOIN) with UNION
  std::string sql = R"(
    -- Left part: all suppliers with their products
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id

    UNION

    -- Right part: all products, including those without suppliers
    SELECT s.name as supplier_name, p.name as product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
  )";

  // Execute the query and return the results
  return db.query<SupProd>(sql);
}

}  // namespace full_join_suppliers_products
```

Both implementations will:
1. Connect to the SQLite database "test_db.sqlite"
2. Perform a FULL JOIN simulation between the Supplier and Product tables
3. Include all suppliers (even those without products) and all products (even those without suppliers)
4. Return the results as a vector of SupProd structs

The key points:
- SQLite doesn't natively support FULL JOIN, so we simulate it using UNION of LEFT JOINs
- The `std::optional<std::string>` for product_name handles cases where a supplier has no products
- The `sqlgen` library's `query<SupProd>()` method automatically maps the SQL results to the C++ struct
- The function returns all rows present in either table, fulfilling the FULL JOIN requirement

