```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  // Create database connection
  sqlgen::database<sqlgen::sqlite> db("test_db.sqlite");

  // Execute the query with GROUP BY and aggregations
  auto results = db.select(
    sqlgen::columns(
      &User::user_id,
      &User::name,
      sqlgen::count(&Post::post_id).as("post_count"),
      sqlgen::avg(sqlgen::length(&Post::content)).as("avg_length")
    ),
    sqlgen::inner_join<Post>(sqlgen::on(&User::user_id == &Post::user_id)),
    sqlgen::group_by(&User::user_id, &User::name)
  );

  // Convert results to Stats objects
  std::vector<Stats> stats;
  for (const auto& row : results) {
    Stats s;
    s.user_id = std::get<0>(row);
    s.name = std::get<1>(row);
    s.post_count = std::get<2>(row);
    s.avg_length = std::get<3>(row);
    stats.push_back(s);
  }

  return stats;
}

}  // namespace group_by_with_aggregations
```

This implementation:

1. **Connects to the SQLite database** using `sqlgen::database<sqlgen::sqlite> db("test_db.sqlite")`

2. **Performs the GROUP BY query** with aggregations using:
   - `sqlgen::count()` to count posts per user
   - `sqlgen::avg(sqlgen::length())` to calculate average content length
   - `sqlgen::inner_join()` to join User and Post tables on user_id
   - `sqlgen::group_by()` to group results by user_id and name

3. **Maps the results** to the `Stats` struct by extracting each column from the result tuple

4. **Returns a vector** of `Stats` objects containing the aggregated data for each user

The query will produce results similar to this SQL:
```sql
SELECT u.user_id, u.name, COUNT(p.post_id) as post_count, AVG(LENGTH(p.content)) as avg_length
FROM User u
INNER JOIN Post p ON u.user_id = p.user_id
GROUP BY u.user_id, u.name
```

